(function(w){"use strict";const ID="average";function compute(x){const raw=String(x.values||"").split(/[\s,]+/).filter(Boolean);const values=raw.map(Number);if(!values.length||values.some(v=>!Number.isFinite(v)))return{error:"숫자를 쉼표 또는 공백으로 구분해 입력해 주세요."};const sum=values.reduce((a,b)=>a+b,0);return{count:values.length,sum,average:sum/values.length}}function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label for="hm-average-values">숫자 입력</label><textarea id="hm-average-values" class="hm-calc-textarea" rows="4" placeholder="예: 10, 20, 30, 40"></textarea><p class="hm-calc-hint">쉼표 또는 공백으로 구분하세요.</p></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">평균 계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const v=root.querySelector("textarea"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({values:v.value});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("평균",api.formatNumber(r.average,6),`<dl><dt>개수</dt><dd>${r.count}개</dd><dt>합계</dt><dd>${api.formatNumber(r.sum,6)}</dd></dl>`));});}w.HM_CALC.register(ID,{compute,render});})(window);
